return $input.all().map(item => ({
  json: {
    evento_id:   String(item.json.id),
    evento_name: item.json.name || '',
    origin:      item.json.origin || 'POA',
    dest:        item.json.airport || '',
    flight_date: String(item.json.flight_date || '').substring(0, 10),
    city:        item.json.city || ''
  }
}));

const httpItems = $input.all();
const ctxItems  = $('Code — Preparar Contexto').all();
const results   = [];

for (let i = 0; i < httpItems.length; i++) {
  const data = httpItems[i].json;
  const ctx  = ctxItems[i]?.json;
  if (!ctx || data.error) continue;

  const all  = [...(data.best_flights || []), ...(data.other_flights || [])];
  if (!all.length) continue;

  const best = all.reduce((a, b) => (!a || b.price < a.price) ? b : a, null);
  if (!best?.price) continue;

  const fl = best.flights || [];
  results.push({ json: {
    evento_id:   ctx.evento_id,
    evento_name: ctx.evento_name,
    airline:     fl[0]?.airline || 'N/D',
    price:       best.price,
    dep_time:    fl[0]?.departure_airport?.time?.slice(11,16) || '',
    arr_time:    (fl[fl.length-1] || fl[0])?.arrival_airport?.time?.slice(11,16) || '',
    stops:       (best.layovers || []).length,
    origin:      ctx.origin,
    dest:        ctx.dest,
    flight_date: ctx.flight_date
  }});
}
return results;

