SELECT COALESCE(
  (SELECT price FROM n8n_monitoramento
   WHERE evento_id = '{{ $json.evento_id }}'
     AND id < {{ $json.id }}
   ORDER BY checked_at DESC
   LIMIT 1),
  NULL
) AS last_price;

