const prevPrices = $input.all();
const flights    = $('Code — Processar Voo').all();
const results    = [];

for (let i = 0; i < flights.length; i++) {
  const flight    = flights[i]?.json;
  const lastPrice = prevPrices[i]?.json?.last_price;
  if (!flight || lastPrice == null) continue;
  if (Number(flight.price) >= Number(lastPrice)) continue;

  const curr   = Number(flight.price);
  const prev   = Number(lastPrice);
  const stopsN = Number(flight.stops);
  const dt     = new Date(flight.flight_date + 'T12:00:00')
                   .toLocaleDateString('pt-BR');

  results.push({ json: {
    evento_id:     flight.evento_id,
    evento_name:   flight.evento_name,
    airline:       flight.airline,
    current_price: curr,
    last_price:    prev,
    dep_time:      flight.dep_time,
    arr_time:      flight.arr_time,
    stops:         stopsN,
    origin:        flight.origin,
    dest:          flight.dest,
    flight_date:   flight.flight_date,
    dt:            dt,
    stops_label:   stopsN === 0 ? 'Voo Direto' : stopsN + ' escala(s)',
    stops_short:   stopsN === 0 ? 'Direto'     : stopsN + ' escala(s)',
    prev_fmt:      prev.toLocaleString('pt-BR', {minimumFractionDigits:2}),
    curr_fmt:      curr.toLocaleString('pt-BR', {minimumFractionDigits:2}),
    email_subject: '\ud83d\udcc9 Queda de pre\u00e7o \u2014 ' + flight.evento_name
  }});
}
return results;

